model = load_model('bidpwl_mip', models_dictionary)
# Heuristic 'cheapest-slope single-tier ladder': for each vendor take its lowest-slope real
# (pl>0) segment; sort vendors by that slope ascending; greedily activate vendors (fix that
# segment's segb=1, all others 0) until cumulative max reach covers req. Unneeded vendors get
# their no-deal segment 0. The solver then sets the segx volumes on the fixed tier pattern.
best = {}
for v in model.v:
    segs = [(s, value(model.pg[v, s]), value(model.px[v, s]) + value(model.pl[v, s]))
            for (vv, s) in model.seg if vv == v and value(model.pl[v, s]) > 0]
    best[v] = min(segs, key=lambda t: t[1])
req = value(model.req)
order = sorted(model.v, key=lambda v: best[v][1])
cum = 0.0
chosen = set()
for v in order:
    if cum >= req:
        break
    chosen.add(v)
    cum += best[v][2]
for v in model.v:
    for (vv, s) in model.seg:
        if vv != v:
            continue
        if v in chosen:
            model.segb[v, s].fix(1 if s == best[v][0] else 0)
        else:
            model.segb[v, s].fix(1 if s == 0 else 0)
description = 'Heuristic: cheapest-slope single-tier vendor ladder'
models_dictionary = solve_model(model, 'bidpwl_mip__heur_cheapslope', models_dictionary, tool_context, description)
print('[HEURISTIC_OBJ] {}'.format(models_dictionary['bidpwl_mip__heur_cheapslope']['obj']['value']))

