model = load_model('epscm_lp', models_dictionary)
# Heuristic renewables-first policy: run the RES units to full capacity on the loads they
# can serve, then backfill each remaining load with the cheapest conventional units in
# merit order, filling each to capacity.
load_order = ['base', 'middle', 'peak']
remaining = {i: value(model.ad) * value(model.df[i]) for i in model.i}
avail = {p: {i for (pp, i) in model.pi if pp == p} for p in model.p}
cap_left = {p: value(model.capacity[p]) for p in model.p}
assign = {(p, i): 0.0 for (p, i) in model.pi}
for i in load_order:
    if i in avail['RES'] and remaining[i] > 1e-9 and cap_left['RES'] > 1e-9:
        take = min(remaining[i], cap_left['RES'])
        assign[('RES', i)] += take
        remaining[i] -= take
        cap_left['RES'] -= take
for p in sorted([u for u in model.p if u != 'RES'], key=lambda u: value(model.cost[u])):
    for i in load_order:
        if i in avail[p] and remaining[i] > 1e-9 and cap_left[p] > 1e-9:
            take = min(remaining[i], cap_left[p])
            assign[(p, i)] += take
            remaining[i] -= take
            cap_left[p] -= take
for (p, i) in model.pi:
    model.x[p, i].fix(assign[(p, i)])
description = 'Heuristic: renewables-first dispatch, conventional backfill in merit order'
models_dictionary = solve_model(model, 'epscm_lp__heur_res_first', models_dictionary, tool_context, description)
print('[HEURISTIC_OBJ] {}'.format(models_dictionary['epscm_lp__heur_res_first']['obj']['value']))

model = load_model('epscmmip_mip', models_dictionary)
# Heuristic 'balanced-density greedy with floor repair': pack items greedily by combined
# value density ((c1+c2) per total resource use) under both knapsacks; if the secondary
# total k2 still falls short of the eps floor, repeatedly swap the chosen item with the
# worst secondary value for the unchosen item with the best secondary value that still
# fits both budgets, until the floor clears. Then fix every item.
J = list(model.J)
res = {j: value(model.a['i1', j]) + value(model.a['i2', j]) for j in J}
dens = {j: (value(model.c1[j]) + value(model.c2[j])) / res[j] for j in J}
cap = {i: value(model.b[i]) for i in model.I}
used = {i: 0.0 for i in model.I}
chosen = set()
def fits_add(j):
    return all(used[i] + value(model.a[i, j]) <= cap[i] for i in model.I)
def add(j):
    chosen.add(j)
    for i in model.I:
        used[i] += value(model.a[i, j])
def remove(j):
    chosen.discard(j)
    for i in model.I:
        used[i] -= value(model.a[i, j])
for j in sorted(J, key=lambda jj: -dens[jj]):
    if fits_add(j):
        add(j)
eps = value(model.eps)
k2 = lambda: sum(value(model.c2[j]) for j in chosen)
while k2() < eps:
    outs = sorted(chosen, key=lambda jj: value(model.c2[jj]))
    ins = sorted((jj for jj in J if jj not in chosen), key=lambda jj: -value(model.c2[jj]))
    improved = False
    for o in outs:
        remove(o)
        for n in ins:
            if value(model.c2[n]) > value(model.c2[o]) and fits_add(n):
                add(n)
                improved = True
                break
        if improved:
            break
        add(o)
    if not improved:
        break
for j in J:
    model.X[j].fix(1 if j in chosen else 0)
description = 'Heuristic: balanced-density greedy with eps-floor repair'
models_dictionary = solve_model(model, 'epscmmip_mip__heur_balanced', models_dictionary, tool_context, description)
print('[HEURISTIC_OBJ] {}'.format(models_dictionary['epscmmip_mip__heur_balanced']['obj']['value']))

