model = load_model('rcpsp_mip', models_dictionary)
import pyomo.environ as pe
jobs = list(model.j)
periods = list(model.t)
dur = {j: int(round(pe.value(model.durations[j]))) for j in jobs}
dem = {(j, r): pe.value(model.demands[j, r]) for j in jobs for r in model.r}
cap = {r: pe.value(model.capacities[r]) for r in model.r}
pred = {}
for (i, j) in model.pred:
    pred.setdefault(j, []).append(i)
T = len(periods)
usage = {(r, k): 0.0 for r in model.r for k in range(1, T + 2)}
finish = {}
for j in jobs:
    est = max([finish[i] for i in pred.get(j, [])], default=0)
    d = dur[j]
    s = est
    while True:
        ok = True
        for k in range(s + 1, s + d + 1):
            for r in model.r:
                if usage[(r, k)] + dem[(j, r)] > cap[r] + 1e-9:
                    ok = False
                    break
            if not ok:
                break
        if ok or d == 0:
            break
        s += 1
    for k in range(s + 1, s + d + 1):
        for r in model.r:
            usage[(r, k)] += dem[(j, r)]
    finish[j] = s + d
for j in jobs:
    f = finish[j]
    target = periods[f]
    feas_t = [t for t in model.t if (j, t) in model.x_index]
    if target not in feas_t:
        cand = [t for t in feas_t if int(t[1:]) >= int(target[1:])]
        target = min(cand, key=lambda t: int(t[1:])) if cand else max(feas_t, key=lambda t: int(t[1:]))
    for t in feas_t:
        model.x[j, t].fix(1 if t == target else 0)
description = 'Heuristic: serial schedule generation scheme (earliest resource-feasible finish, jobs in listed order)'
models_dictionary = solve_model(model, 'rcpsp_mip__heur_serial', models_dictionary, tool_context, description)
print('[HEURISTIC_OBJ] {}'.format(models_dictionary['rcpsp_mip__heur_serial']['obj']['value']))

