model = load_model('stablem_mip', models_dictionary)
# Heuristic 'man-proposing Gale-Shapley': run classic deferred acceptance with the MEN
# proposing -- each man asks down his own preference list, each woman provisionally holds
# her best current suitor by her ranking. This yields the man-optimal / woman-pessimal
# stable matching; fix match to it and let the solver read off the woman-rank.
men = list(model.m); women = list(model.w)
mpref = {man: sorted(women, key=lambda w: value(model.mp[man, w])) for man in men}
free = list(men); nextprop = {man: 0 for man in men}; engaged = {}
while free:
    man = free.pop(0)
    w = mpref[man][nextprop[man]]; nextprop[man] += 1
    if w not in engaged:
        engaged[w] = man
    else:
        cur = engaged[w]
        if value(model.wp[w, man]) < value(model.wp[w, cur]):
            engaged[w] = man; free.append(cur)
        else:
            free.append(man)
for w in women:
    for man in men:
        model.match[w, man].fix(1 if engaged[w] == man else 0)
description = 'Heuristic: man-proposing Gale-Shapley (man-optimal stable matching)'
models_dictionary = solve_model(model, 'stablem_mip__heur_manopt', models_dictionary, tool_context, description)
print('[HEURISTIC_OBJ] {}'.format(models_dictionary['stablem_mip__heur_manopt']['obj']['value']))

